select s.id, s.task_id, s.trace_id, s.document_id, t.file_name, t.document_type, t.source_type, t.business_no, s.target_table, s.mapping_profile, s.storage_json, s.unique_key_json, s.storage_status, s.duplicate_strategy, s.error_message, s.stored_by, s.stored_at, s.created_at, s.updated_at from storage_result_record s left join extract_task t on s.task_id = t.task_id
and s.target_table = #{query.targetTable}
and s.storage_status = #{query.storageStatus}
and t.document_type = #{query.documentType}
and t.source_type = #{query.sourceType}
and (s.task_id like #{keywordLike} or s.trace_id like #{keywordLike} or s.document_id like #{keywordLike} or t.file_name like #{keywordLike} or t.business_no like #{keywordLike})
order by s.stored_at desc, s.updated_at desc

